import{_ as e,o,c as i,ag as a}from"./chunks/framework-C5-Jzrz4.js";const l=JSON.parse('{"title":"环境变量与代理","description":"web-antd 环境变量来源、生产注入与代理路径说明","frontmatter":{"title":"环境变量与代理","description":"web-antd 环境变量来源、生产注入与代理路径说明"},"headers":[],"relativePath":"scripts/deployment/环境变量与代理.md","filePath":"scripts/deployment/环境变量与代理.md","lastUpdated":null}');const d=e({name:"scripts/deployment/环境变量与代理.md"},[["render",function(e,l,d,c,t,r){return o(),i("div",null,[...l[0]||(l[0]=[a('<h1 id="环境变量与代理" tabindex="-1">环境变量与代理 <a class="header-anchor" href="#环境变量与代理" aria-label="Permalink to &quot;环境变量与代理&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本页说明部署时最容易出错的两类配置：环境变量与反向代理路径。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>生产部署配置</li><li>代理路径联调</li><li>SSE/WebSocket 反向代理检查</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/.env.production</code></li><li><code>apps/web-antd/.env.test</code></li><li><code>packages/effects/hooks/src/use-app-config.ts</code></li><li><code>apps/web-antd/vite.config.ts</code></li><li><code>scripts/deploy/nginx.conf</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="环境变量解析" tabindex="-1">环境变量解析 <a class="header-anchor" href="#环境变量解析" aria-label="Permalink to &quot;环境变量解析&quot;">​</a></h3><p><code>useAppConfig</code> 会读取：</p><ul><li><code>VITE_GLOB_API_URL</code></li><li><code>VITE_GLOB_APP_CLIENT_ID</code></li><li><code>VITE_GLOB_ENABLE_ENCRYPT</code></li><li><code>VITE_GLOB_RSA_PUBLIC_KEY</code></li><li><code>VITE_GLOB_RSA_PRIVATE_KEY</code></li><li><code>VITE_GLOB_SSE_ENABLE</code></li><li><code>VITE_GLOB_WEBSOCKET_ENABLE</code></li></ul><p>生产环境下这些值来自 <code>window._VBEN_ADMIN_PRO_APP_CONF_</code>。</p><h3 id="开发代理" tabindex="-1">开发代理 <a class="header-anchor" href="#开发代理" aria-label="Permalink to &quot;开发代理&quot;">​</a></h3><p><code>apps/web-antd/vite.config.ts</code> 当前配置：</p><ul><li><code>/api -&gt; http://localhost:8080</code></li><li><code>rewrite(/^\\/api/, &#39;&#39;)</code></li><li><code>ws: true</code></li></ul><h3 id="nginx-生产代理" tabindex="-1">Nginx 生产代理 <a class="header-anchor" href="#nginx-生产代理" aria-label="Permalink to &quot;Nginx 生产代理&quot;">​</a></h3><p><code>scripts/deploy/nginx.conf</code> 当前配置重点：</p><ul><li>前端路由回退：<code>try_files $uri $uri/ /index.html</code></li><li>后端代理：<code>/prod-api/</code> -&gt; <code>upstream server</code></li><li>SSE/WebSocket 支持： <ul><li><code>proxy_http_version 1.1</code></li><li><code>Upgrade</code>/<code>Connection</code> 头透传</li><li><code>proxy_buffering off</code></li></ul></li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>如果前端 <code>base</code> 为 <code>/vben</code>，Nginx 的静态目录与回退路径要保持一致。</li><li>若启用 SSE/WebSocket，反向代理必须保留升级头和长连接超时设置。</li><li><code>VITE_GLOB_API_URL</code> 与反向代理路径应统一设计，避免“前端直连 + 代理”混用。</li></ul>',20)])])}]]);export{l as __pageData,d as default};
